import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    conn = psycopg2.connect("dbname=yourdbname user=youruser password=yourpassword")
    cursor = conn.cursor()
    
    query = "SELECT * FROM users WHERE TRUE"
    params = []

    if username:
        query += " AND username = %s"
        params.append(username)
    if email:
        query += " AND email = %s"
